mapper.update:
update dish set name = #{name}, category_id = #{categoryId}, price = #{price}, image = #{image}, description = #{description},
                status = #{status}, update_time = #{updateTime}, update_user = #{updateUser}
where id = #{id}

mapper.select:
select dish.* , category.name as category_name from dish left join category on dish.category_id = category.id


    and category_id = #{categoryId}


    and dish.name like concat('%',#{name},'%')


    and dish.status = #{status}


order by category_id desc , dish.update_time desc
